document.addEventListener("DOMContentLoaded",()=>{const t=document.getElementById("btn-extract"),e=document.getElementById("status");t.addEventListener("click",()=>{e.textContent="Extracting...",chrome.runtime.sendMessage({action:"EXTRACT_DOM"},t=>{chrome.runtime.lastError?e.textContent="Error: "+chrome.runtime.lastError.message:"error"!==t.status?setTimeout(()=>{chrome.storage.local.get("extractedData",t=>{const n=t.extractedData;e.textContent=n?.length?"Extracted "+n.length+" turns":"No conversation found on this page"})},500):e.textContent="Failed: "+t.reason})})});